import { buildMarkerBrightnessState } from './build-marker-brightness-state.js';
import type { MarkerInteractionState } from '../types/marker.js';
import type { SelectionState } from '../types/state.js';

/**
 * Determines the brightness interaction state of a marker based on the current selection.
 * @param markerId - The id of the marker to evaluate.
 * @param selection - The current annotations selection state containing hover and pinned information.
 * @returns The marker's interaction state (`'default'` | `'hovered'` | `'active'` | `'inactive'`).
 * @internal
 */
export const defineMarkerBrightnessState = (
  markerId: string,
  selection: SelectionState,
): MarkerInteractionState => {
  const isListHovered = selection.hoverGroupListKey === markerId;

  return buildMarkerBrightnessState(selection, markerId, isListHovered);
};
